import{_ as e,o as t,c as s,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"FAQ & トラブルシューティング","description":"","frontmatter":{},"headers":[],"relativePath":"ja/faq.md","filePath":"ja/faq.md"}'),l={name:"ja/faq.md"};function i(c,a,r,d,n,m){return t(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="faq-トラブルシューティング" tabindex="-1"><i class="ph ph-question"></i> FAQ &amp; トラブルシューティング <a class="header-anchor" href="#faq-トラブルシューティング" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-question&quot;&gt;&lt;/i&gt; FAQ &amp; トラブルシューティング&quot;">​</a></h1><p>このセクションでは、WebGL最適化中によく発生する問題の解決策と、よくある質問への回答をまとめています。</p><h2 id="インストールとデモシーン" tabindex="-1"><i class="ph ph-package"></i> インストールとデモシーン <a class="header-anchor" href="#インストールとデモシーン" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-package&quot;&gt;&lt;/i&gt; インストールとデモシーン&quot;">​</a></h2><details class="details custom-block"><summary>Q: デモシーンを開いたら、すべてのマテリアルとオブジェクトがピンク色です！</summary><p><strong>A:</strong> プロジェクトがURPを使用しているのに対し、デモシーンはデフォルトでBiRP用に設定されているためです。<code>WebAdaptivePerformance/Demo/Import Me (URP).unitypackage</code> にあるパッケージを解凍してください。シェーダーが自動的に更新されます。</p></details><details class="details custom-block"><summary>Q: プラグインをインストールしましたが、ゲーム内で視覚的に何も変わりません。</summary><p><strong>A:</strong> 以下のチェックリストを確認してください：</p><ul><li>Project Settingsでプラグインが有効になっていますか？スケーラーは追加され、アクティブになっていますか？</li><li>Unityのグラフィック設定は最初から最大に設定されていますか？設定がすでに低い場合、プラグインが下げるものはありません。</li><li>おそらく、デバイスが負荷を完璧に処理しており、FPSが安定しているのでしょう。<code>Dashboard</code> プレハブをシーンに追加して、インデクサーの現在の決定を監視してみてください。</li><li>すべてが正しく設定されているのに効果がない場合は、お問い合わせください。トラブルシューティングをお手伝いします。</li></ul></details><h2 id="解像度とインターフェース-ui" tabindex="-1"><i class="ph ph-monitor-play"></i> 解像度とインターフェース (UI) <a class="header-anchor" href="#解像度とインターフェース-ui" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-monitor-play&quot;&gt;&lt;/i&gt; 解像度とインターフェース (UI)&quot;">​</a></h2><details class="details custom-block"><summary>Q: 解像度が変わりません (Resolution Scaler がアクティブになりません)。</summary><p><strong>A:</strong> 最も一般的な2つの理由は以下の通りです：</p><ol><li><strong>BiRP</strong> を使用しており、<code>RenderTextureScaling</code> モードの場合：スケーラー設定内の <code>Target Tags</code> 配列を確認してください。ゲームのカメラの名前が異なる場合（<code>MainCamera</code> ではない場合）、そのタグを挿入する必要があります。そうしないと、プラグインはそれを見つけることができません。</li><li><code>NativeBrowserScaling</code> モードは、ビルドされたWebGLレンダリング環境でのみ動作します。Unity Editor内では何も行いません。</li></ol></details><details class="details custom-block"><summary>Q: FPSが下がると、UIも歪んだりぼやけたりします！</summary><p><strong>A:</strong> BiRPで <code>RenderTextureScaling</code> が選択されていることを確認してください。Canvas自体は <code>Screen Space - Overlay</code> モードで設定されている必要があります（またはUI専用のカメラを使用する必要があります）。</p></details><details class="details custom-block"><summary>Q: 標準のUIボタンは正常に動作しますが、3Dオブジェクトへのマウスクリック（カスタムのRaycast）がおかしくなります。</summary><p><strong>A:</strong> 標準の EventSystem イベントは、当社の <code>WebScaledPhysicsRaycaster</code> コンポーネントによってシームレスに修正されます。ただし、コードを通じて手動でレイキャスト（Raycast）を呼び出す場合（<code>Camera.ScreenPointToRay()</code>）、画面の解像度がレンダリングされたものと一致しないため、クリック座標の取得に失敗します。この目的のために、当社のプラグインのメソッドを使用してください：<code>WebRaycasterUtility.TryComputeScaledRay()</code>。</p></details><h2 id="メトリクスとシステムの動作" tabindex="-1"><i class="ph ph-chart-line-up"></i> メトリクスとシステムの動作 <a class="header-anchor" href="#メトリクスとシステムの動作" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-line-up&quot;&gt;&lt;/i&gt; メトリクスとシステムの動作&quot;">​</a></h2><details class="details custom-block"><summary>Q: 遅延によりグラフィック品質が低下しました。現在FPSは再び高くなりましたが、グラフィックが回復しません！</summary><p><strong>A:</strong> <strong>アンチヨーヨー・ペナルティシステム (Anti Yo-Yo Penalty System)</strong> がアクティブになった可能性が非常に高いです。プラグインは、不安定さ（Quality flickering）を防ぐために、視覚的な向上を一時的にブロックしました。</p><ul><li>グラフィックをより早く安定させたい場合は、<code>Penalty Lockout Duration</code> パラメータの制限を減らしてください（例：10秒に設定）。</li><li>また、<code>Increase Cooldown</code> も確認してください。待機時間が長すぎる可能性があります。</li></ul></details><details class="details custom-block"><summary>Q: シーンが空であるにもかかわらず、ダッシュボードに継続的に CPU Bottleneck (CPUボトルネック) または Unknown と表示されます。</summary><p><strong>A:</strong> Player Settingsで <code>Frame Timing Stats</code> を有効にすることを忘れないでください。その後、<code>Application.targetFrameRate = -1</code> となっているか確認してください。時間のリフレッシュの制限を解除することで、メトリクスを解放し、ブラウザの <code>setTimeout</code> による減速から隔離します。</p></details><details class="details custom-block"><summary>Q: キャラクター（または物理プロップ）が激しくカクついたり、「ラグ (lags)」が発生したりします。</summary><p><strong>A:</strong> これは、<code>Physics Step Scaler</code> が強制的に有効になったことによる副作用です。極端なパフォーマンス低下時にCPUがフリーズするのを防ぐために、<code>Time.fixedDeltaTime</code> のベースラインを調整します。シーン内の各キャラクターの <code>Rigidbody</code> コンポーネントタブにある <code>Interpolate</code>（または Extrapolate）設定を即座にオンにすることで、純粋に滑らかな移行を確保してください。</p></details><details class="details custom-block"><summary>Q: Shadow Scalers (シャドウ) が有効になっていますが、パフォーマンスは低下し続け、シャドウはそのまま残っています。</summary><p><strong>A:</strong> これらのモジュールは、リアルタイム（Realtime）の動的シャドウと照明のみを監視および操作します。照明設定が「事前計算済み (Baked/Lightmaps)」としてマークされている場合、ツールはそれに影響を与えません。</p></details><h2 id="カスタムスケーラー-custom-scalers" tabindex="-1"><i class="ph ph-code"></i> カスタムスケーラー (Custom Scalers) <a class="header-anchor" href="#カスタムスケーラー-custom-scalers" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-code&quot;&gt;&lt;/i&gt; カスタムスケーラー (Custom Scalers)&quot;">​</a></h2><details class="details custom-block"><summary>Q: 独自のカスタムスケーラーはエディターモードでは見事に機能しますが、WebGLビルドバージョンでは完全に消滅してしまいます！</summary><p><strong>A:</strong> 通常の内部手順において、IL2CPPアーキテクチャインテグレータがそれを未使用のコード（&quot;dead code&quot;）とみなして消去したためです。作成したカスタムスケーラーのメインクラスの上部に、必須の <code>[UnityEngine.Scripting.Preserve]</code> 属性を強制的に含めてください。</p></details>',16)])])}const h=e(l,[["render",i]]);export{p as __pageData,h as default};
